import{_ as i,o as a,c as l,ag as o}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"SDK 开发者指南","description":"","frontmatter":{},"headers":[],"relativePath":"sdk.md","filePath":"sdk.md","lastUpdated":1774505084000}'),d={name:"sdk.md"};function c(s,e,r,t,p,n){return a(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="sdk-开发者指南" tabindex="-1">SDK 开发者指南 <a class="header-anchor" href="#sdk-开发者指南" aria-label="Permalink to &quot;SDK 开发者指南&quot;">​</a></h1><p>这一页记录的是把设备接入 <code>ModLink Studio</code> 时最常用的约定。</p><p>目前的 SDK 重点是把 driver 开发收敛成一组足够小、但又能覆盖常见设备形态的接口。对大多数设备来说，判断通常先从这里开始：</p><ul><li>常见轮询设备优先考虑 <code>LoopDriver</code></li><li>callback 型设备直接继承 <code>Driver</code></li></ul><h2 id="快速定位" tabindex="-1">快速定位 <a class="header-anchor" href="#快速定位" aria-label="Permalink to &quot;快速定位&quot;">​</a></h2><p>这一页主要分成下面几部分：</p><ul><li><a href="#先选哪一个基类">先选哪一个基类</a></li><li><a href="#最小接入流程">最小接入流程</a></li><li><a href="#三个核心数据模型">三个核心数据模型</a></li><li><a href="#driver-生命周期">driver 生命周期</a></li><li><a href="#插件项目怎么组织">插件项目怎么组织</a></li><li><a href="#命名建议">命名建议</a></li></ul><h2 id="先选哪一个基类" tabindex="-1">先选哪一个基类 <a class="header-anchor" href="#先选哪一个基类" aria-label="Permalink to &quot;先选哪一个基类&quot;">​</a></h2><h3 id="driver" tabindex="-1"><code>Driver</code> <a class="header-anchor" href="#driver" aria-label="Permalink to &quot;`Driver`&quot;">​</a></h3><p><code>Driver</code> 是最通用的基础契约。</p><p>适合这类设备：</p><ul><li>callback 型 SDK</li><li>比较特殊的第三方库</li><li>一个固定 <code>loop()</code> 很难表达清楚的设备</li></ul><p>常见实现点包括：</p><ul><li><code>search()</code></li><li><code>connect_device()</code></li><li><code>disconnect_device()</code></li><li><code>start_streaming()</code></li><li><code>stop_streaming()</code></li><li><code>descriptors()</code></li></ul><h3 id="loopdriver" tabindex="-1"><code>LoopDriver</code> <a class="header-anchor" href="#loopdriver" aria-label="Permalink to &quot;`LoopDriver`&quot;">​</a></h3><p><code>LoopDriver</code> 是给常见轮询型设备准备的轻量 helper。</p><p>适合这类设备：</p><ul><li>串口轮询</li><li>BrainFlow 这类“先看有没有数据，再取数据”的设备</li><li>协议本身天然就是一个短循环的设备</li></ul><p>常见实现点包括：</p><ul><li><code>search()</code></li><li><code>connect_device()</code></li><li><code>disconnect_device()</code></li><li><code>descriptors()</code></li><li><code>loop()</code></li></ul><p>可选实现：</p><ul><li><code>on_loop_started()</code></li><li><code>on_loop_stopped()</code></li><li><code>loop_interval_ms</code></li></ul><p><code>LoopDriver</code> 已经满足普通 <code>Driver</code> 契约，所以当前 runtime 不需要额外适配它。</p><h2 id="最小接入流程" tabindex="-1">最小接入流程 <a class="header-anchor" href="#最小接入流程" aria-label="Permalink to &quot;最小接入流程&quot;">​</a></h2><p>不管最终选哪一个基类，最小接入流程都差不多：</p><ol><li>定义一个 driver 类</li><li>实现 <code>device_id</code></li><li>实现 <code>descriptors()</code></li><li>实现 <code>search()</code></li><li>实现连接和采集逻辑</li><li>通过 <code>sig_frame</code> 发出 <code>FrameEnvelope</code></li></ol><p>如果目的是先把链路跑通，最值得先定住的是这两件事：</p><ul><li><code>StreamDescriptor</code></li><li><code>FrameEnvelope.data</code> 的 shape</li></ul><p>一旦这两件事稳定下来，UI、录制和调试路径通常也会稳定很多。</p><h2 id="三个核心数据模型" tabindex="-1">三个核心数据模型 <a class="header-anchor" href="#三个核心数据模型" aria-label="Permalink to &quot;三个核心数据模型&quot;">​</a></h2><h3 id="searchresult" tabindex="-1"><code>SearchResult</code> <a class="header-anchor" href="#searchresult" aria-label="Permalink to &quot;`SearchResult`&quot;">​</a></h3><p><code>search()</code> 返回的是一组 <code>SearchResult</code>。</p><p>它的职责很简单：</p><ul><li><code>title</code> / <code>subtitle</code> 给界面展示</li><li><code>extra</code> 给 driver 自己使用</li></ul><p>宿主不会解析 <code>extra</code>，只是把它原样传回 <code>connect_device()</code>。</p><h3 id="streamdescriptor" tabindex="-1"><code>StreamDescriptor</code> <a class="header-anchor" href="#streamdescriptor" aria-label="Permalink to &quot;`StreamDescriptor`&quot;">​</a></h3><p><code>StreamDescriptor</code> 描述的是“这个 driver 会发哪些流”。</p><p>最常用的字段是：</p><ul><li><code>stream_id</code></li><li><code>modality</code></li><li><code>payload_type</code></li><li><code>nominal_sample_rate_hz</code></li><li><code>chunk_size</code></li><li><code>channel_names</code></li><li><code>unit</code></li></ul><p>这里有一个当前实现上的边界：</p><ul><li>host 可能会在设备连接前就读取 descriptor</li><li>所以 <code>descriptors()</code> 最好不要依赖“必须先连上设备才能知道”的动态状态</li></ul><h3 id="frameenvelope" tabindex="-1"><code>FrameEnvelope</code> <a class="header-anchor" href="#frameenvelope" aria-label="Permalink to &quot;`FrameEnvelope`&quot;">​</a></h3><p><code>FrameEnvelope</code> 是 driver 在运行时真正发出的数据块。</p><p>可以把它理解成：</p><ul><li><code>stream_id</code>：这块数据属于哪个流</li><li><code>timestamp_ns</code>：这块数据对应的时间戳</li><li><code>data</code>：数据本体</li><li><code>seq</code>：可选顺序号</li></ul><h2 id="driver-生命周期" tabindex="-1">driver 生命周期 <a class="header-anchor" href="#driver-生命周期" aria-label="Permalink to &quot;driver 生命周期&quot;">​</a></h2><p>宿主对 driver 的典型调用顺序是：</p><ol><li>创建 driver</li><li>读取 <code>device_id</code> / <code>display_name</code></li><li>读取 <code>descriptors()</code></li><li>启动 driver worker thread</li><li>调 <code>search()</code></li><li>调 <code>connect_device()</code></li><li>调 <code>start_streaming()</code></li><li>后续调 <code>stop_streaming()</code> / <code>disconnect_device()</code> / <code>shutdown()</code></li></ol><p>从 driver 侧看，最重要的边界是：</p><ul><li><code>search()</code> 负责一次性发现</li><li><code>connect_device()</code> 负责建立连接，但不开始实时采集</li><li><code>start_streaming()</code> 负责开始发 <code>FrameEnvelope</code></li><li><code>stop_streaming()</code> 负责停止发流</li></ul><p>继承 <code>LoopDriver</code> 时，第 7 步里的 <code>start_streaming()</code> 已经由基类实现，driver 只需要写 <code>loop()</code> 即可。</p><h2 id="frameenvelope-data-的常见-shape" tabindex="-1"><code>FrameEnvelope.data</code> 的常见 shape <a class="header-anchor" href="#frameenvelope-data-的常见-shape" aria-label="Permalink to &quot;`FrameEnvelope.data` 的常见 shape&quot;">​</a></h2><p>这个项目当前最常见的是 <code>line</code> 类型流。</p><p>建议约定：</p><ul><li><code>line</code>: <code>[channel_count, chunk_size]</code></li></ul><p>常见例子：</p><ul><li>EEG 多通道数据</li><li>PPG / ECG 多通道数据</li><li>加速度计 <code>x/y/z</code></li></ul><p>同一个设备、同一种模态下的多个 channel，通常更适合放在<strong>同一个 stream</strong>里，而不是拆成多个 stream。</p><h2 id="插件项目怎么组织" tabindex="-1">插件项目怎么组织 <a class="header-anchor" href="#插件项目怎么组织" aria-label="Permalink to &quot;插件项目怎么组织&quot;">​</a></h2><p>当前推荐把具体设备插件放在 <code>plugins/</code> 下，每个插件是一个独立项目。</p><p>最小结构可以是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>plugins/</span></span>\n<span class="line"><span>└─ your_device/</span></span>\n<span class="line"><span>   ├─ pyproject.toml</span></span>\n<span class="line"><span>   └─ your_device/</span></span>\n<span class="line"><span>      ├─ __init__.py</span></span>\n<span class="line"><span>      ├─ factory.py</span></span>\n<span class="line"><span>      └─ driver.py</span></span></code></pre></div><p>其中：</p><ul><li><code>factory.py</code> 提供零参数 <code>create_driver()</code></li><li><code>pyproject.toml</code> 里通过 <code>modlink.drivers</code> 注册 entry point</li></ul><p>当前推荐启动方式不是把插件装进根 workspace，而是运行时临时附加：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --with</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./plugins/openbciganglion</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink-studio</span></span></code></pre></div><p>开发插件时则用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --with-editable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./plugins/openbciganglion</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink-studio</span></span></code></pre></div><h2 id="命名建议" tabindex="-1">命名建议 <a class="header-anchor" href="#命名建议" aria-label="Permalink to &quot;命名建议&quot;">​</a></h2><h3 id="device-id" tabindex="-1"><code>device_id</code> <a class="header-anchor" href="#device-id" aria-label="Permalink to &quot;`device_id`&quot;">​</a></h3><p>建议表达“这是哪个 driver 的第几个设备实例”，并保持稳定。</p><p>推荐格式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>name.XX</span></span></code></pre></div><p>其中：</p><ul><li><code>name</code> 用 driver 名字的规范化 token，例如 <code>openbciganglion</code></li><li><code>XX</code> 用两位及以上数字表示实例序号，例如 <code>01</code>、<code>02</code></li></ul><p>例如：</p><ul><li><code>openbciganglion.01</code></li><li><code>microphone_demo.01</code></li></ul><h3 id="stream-id" tabindex="-1"><code>stream_id</code> <a class="header-anchor" href="#stream-id" aria-label="Permalink to &quot;`stream_id`&quot;">​</a></h3><p><code>stream_id</code> 不建议手写，当前约定是由 <code>device_id + modality</code> 自动派生：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{device_id}:{modality}</span></span></code></pre></div><p>例如：</p><ul><li><code>openbciganglion.01:eeg</code></li><li><code>microphone_demo.01:audio</code></li></ul><h2 id="什么时候不要急着抽新基类" tabindex="-1">什么时候不要急着抽新基类 <a class="header-anchor" href="#什么时候不要急着抽新基类" aria-label="Permalink to &quot;什么时候不要急着抽新基类&quot;">​</a></h2><p>对于 callback 型设备，直接继承 <code>Driver</code> 往往会更干净。</p><p>原因很简单：</p><ul><li><code>LoopDriver</code> 的公共模式非常稳定</li><li>callback 型设备的启动、注册和停止方式差异更大</li></ul><p>所以当前 SDK 的策略是：</p><ul><li>对最常见的轮询设备，先提供 <code>LoopDriver</code></li><li>对 callback 型设备，先保留基础 <code>Driver</code></li></ul><p>等真的出现了稳定的 callback 共性，再考虑要不要抽新的 helper。</p>',89)])])}const v=i(d,[["render",c]]);export{u as __pageData,v as default};
